/**
* Try to optimize the window conditions.
*
* @param session
*            the session
*/
    public void optimize(SessionLocal session) {
        if (partitionBy != null) {
            for (ListIterator<Expression> i = partitionBy.listIterator(); i.hasNext();) {
                Expression e = i.next().optimize(session);
                if (e.isConstant()) {
                    i.remove();
                } else {
                    i.set(e);
                }
            }
            if (partitionBy.isEmpty()) {
                partitionBy = null;
            }
        }
        if (orderBy != null) {
            for (Iterator<QueryOrderBy> i = orderBy.iterator(); i.hasNext();) {
                QueryOrderBy o = i.next();
                Expression e = o.expression.optimize(session);
                if (e.isConstant()) {
                    i.remove();
                } else {
                    o.expression = e;
                }
            }
            if (orderBy.isEmpty()) {
                orderBy = null;
            }
        }
        if (frame != null) {
            frame.optimize(session);
        }
    }

    public Expression optimize(SessionLocal session) {
        if (over != null) {
            over.optimize(session);
            ArrayList<QueryOrderBy> orderBy = over.getOrderBy();
            if (orderBy != null) {
                overOrderBySort = createOrder(session, orderBy, getNumExpressions());
            } else if (!isAggregate()) {
                overOrderBySort = new SortOrder(session, new int[getNumExpressions()]);
            }
            WindowFrame frame = over.getWindowFrame();
            if (frame != null) {
                int index = getNumExpressions();
                int orderBySize = 0;
                if (orderBy != null) {
                    orderBySize = orderBy.size();
                    index += orderBySize;
                }
                int n = 0;
                WindowFrameBound bound = frame.getStarting();
                if (bound.isParameterized()) {
                    checkOrderBy(frame.getUnits(), orderBySize);
                    if (bound.isVariable()) {
                        bound.setExpressionIndex(index);
                        n++;
                    }
                }
                bound = frame.getFollowing();
                if (bound != null && bound.isParameterized()) {
                    checkOrderBy(frame.getUnits(), orderBySize);
                    if (bound.isVariable()) {
                        bound.setExpressionIndex(index + n);
                        n++;
                    }
                }
                numFrameExpressions = n;
            }
        }
        return this;
    }

