            type = field == EPOCH ? TypeInfo.getTypeInfo(Value.NUMERIC,
                    ValueBigint.DECIMAL_PRECISION + ValueTimestamp.MAXIMUM_SCALE, ValueTimestamp.MAXIMUM_SCALE, null)
                    : TypeInfo.TYPE_INTEGER;
